import { toDecimalFeet } from './units'

export interface FlooringInput {
  lengthFt: number
  lengthIn: number
  widthFt: number
  widthIn: number
  wastePct: number
  boxCoverage: number // æŊįŪąčĶį sq ft
}

export interface FlooringResult {
  roomArea: number // æŋéīåéĒį§Ŋ sq ft
  needed: number // åŦæčįčī­äđ°é sq ft
  boxes: number
  boxCoverage: number // åŪéä―ŋįĻįįŪąčĶįįïžåæūïž
}

const DEFAULT_BOX_COVERAGE = 20 // sq ftïžåžšå/äđįŊåšæŋåļļč§č§æ ž

/** æ æčūåĨïžæŋéīå°šåŊļäļš 0ïžæķčŋå nullïžįą UI æūįĪšå ä― */
export function calcFlooring(i: FlooringInput): FlooringResult | null {
  const length = toDecimalFeet(i.lengthFt, i.lengthIn)
  const width = toDecimalFeet(i.widthFt, i.widthIn)

  if (length <= 0 || width <= 0) return null

  const roomArea = length * width
  const needed = roomArea * (1 + Math.max(0, i.wastePct) / 100)
  // įŪąčĶįįäļšįĐš/äļš 0 æķæåļļč§éŧčŪĪ 20 sq ft čŪĄïžéŋåéĪéķ
  const boxCoverage = i.boxCoverage > 0 ? i.boxCoverage : DEFAULT_BOX_COVERAGE

  return {
    roomArea,
    needed,
    boxes: Math.ceil(needed / boxCoverage),
    boxCoverage,
  }
}
